// Social system constants + view types single source of truth (SOCIAL_DESIGN.md, S6-0).
// Pure data, no DB / no PIXI. meta uses this for server-side validation of friends/chat/mail;
// client REST DTOs are generated by openapi-typescript from openapi.yml (semantically consistent with this file).
// Collection document shapes (FriendEdgeDoc/ConversationDoc/MailDoc…) live in mongo.ts, following the existing SaveDoc convention.
import type { EquipmentInstance, CardInstance } from './types';

// ── Caps / quotas ──────────────────────────────────────
/** Maximum number of friends (requests/accepts are rejected when the cap is reached, SOC6). */
export const FRIEND_CAP = 100;
/** Maximum length of the friend-request message. */
export const FRIEND_REQUEST_MESSAGE_MAX = 200;

/** Retention duration for chat messages (seconds); used by the TTL index on ChatMessageDoc (SOC4). */
export const CHAT_RETENTION_SEC = 30 * 24 * 3600;
/** Maximum body length of a single chat message. */
export const CHAT_BODY_MAX = 500;
/** Chat send rate limit: maximum messages per account per minute (RATE_LIMITED, SOC2). */
export const CHAT_SEND_RATE_PER_MIN = 30;
/** Maximum number of messages per page when fetching history. */
export const CHAT_HISTORY_PAGE_MAX = 50;

/** Default mail TTL (seconds); MailDoc.expireAt defaults to now + this value; auto-reclaimed by TTL index (SOC5). */
export const MAIL_DEFAULT_TTL_SEC = 30 * 24 * 3600;
export const MAIL_SUBJECT_MAX = 80;
export const MAIL_BODY_MAX = 2000;

// ── Deterministic id derivation (no lookup required; computable by either side) ──────────────
/**
 * Chat conversation id: two accountIds sorted and concatenated (SOC4). Either party can derive
 * the same convId without first querying the database to create the conversation.
 */
export function conversationId(a: string, b: string): string {
  return a < b ? `${a}:${b}` : `${b}:${a}`;
}

/** Directed friend-edge id (from owner's perspective; mutual friendship = two edges, SOC6). */
export function friendEdgeId(owner: string, friend: string): string {
  return `${owner}:${friend}`;
}

/** Directed block-edge id. */
export function blockId(owner: string, target: string): string {
  return `${owner}:${target}`;
}

// ── View types (REST response shapes; openapi schema is semantically equivalent) ────────────
/** Public profile (returned by publicId search / profile card). Never contains accountId. */
export interface ProfileView {
  publicId: string;
  displayName: string;
  rank?: string;
  /** Equipped title (称号), if any. */
  equippedTitle?: string;
  /** Equipped avatar (composite "<category>:<key>", see avatar.ts), if any. */
  avatarId?: string;
}

export interface FriendView {
  publicId: string;
  displayName: string;
  online: boolean;
  rank?: string;
  /** Owner-private alias for the friend. */
  alias?: string;
  /** Equipped avatar (composite "<category>:<key>", see avatar.ts), if any. */
  avatarId?: string;
}

export interface FriendRequestView {
  requestId: string;
  fromPublicId: string;
  fromName: string;
  toPublicId: string;
  message?: string;
  createdAt: number;
}

export interface ConversationView {
  convId: string;
  /** Public profile of the conversation peer. */
  peer: ProfileView;
  lastBody?: string;
  lastFrom?: string;
  lastTs: number;
  unread: number;
}

export interface ChatMessageView {
  messageId: string;
  convId: string;
  fromPublicId: string;
  body: string;
  kind: 'text' | 'system';
  ts: number;
}

// 'material' = progression materials (scrap/lead/binding), delivered to the SaveData.materials shared pool
// (used by PvE/equipment/auction, SLG8 unified material flow); 'item' goes into the inventory.items general bucket.
// The two buckets are intentionally separate — materials must not be mixed with general items.
// 'equipment'/'card' carry a full instance snapshot (auction escrow-out delivery/return); the client renders
// name/rarity/level directly from the attached instance and the claim writes it back to equipmentInv/cardInv.
export type MailAttachmentKind = 'coins' | 'item' | 'skin' | 'material' | 'equipment' | 'card';
export interface MailAttachmentView {
  kind: MailAttachmentKind;
  id?: string;
  count?: number;
  // Present only for kind 'equipment' | 'card': the traded instance snapshot (used for client-side display).
  instance?: EquipmentInstance | CardInstance;
}

export interface MailView {
  mailId: string;
  from: 'system' | string; // 'system' or sender publicId
  fromName?: string;
  subject: string;
  body: string;
  attachments?: MailAttachmentView[];
  createdAt: number;
  expireAt: number;
  read: boolean;
  claimed: boolean;
}

/**
 * Offline badge aggregation (SOCIAL_DESIGN §6 UI "top/bottom-bar total unread badge", SOC8).
 * Fetched once on login; subsequently updated incrementally on the client via social pushes
 * (friend_request / chat_message / mail_new).
 * Each field is a "count" value, not a raw message total: `friendRequests` = number of pending
 * incoming requests; `chat` = number of conversations with unread messages; `mail` = number of
 * unread, non-expired mails; `total` = sum of all three, used for a single aggregate badge.
 * Uses lightweight aggregation queries (countDocuments); does not fetch full friends/conversations/mail lists.
 */
export interface SocialBadges {
  friendRequests: number;
  chat: number;
  mail: number;
  total: number;
}
